// Error reporter: recover Slack thread + channel from failed execution (API includeData).

const errorMeta = $('Error Trigger').first().json || {};
const exec = errorMeta.execution || {};
const wf = errorMeta.workflow || {};
const cfg = $('Config').first().json || {};

const apiResp = $input.first().json || {};
const runData =
  (apiResp.data && apiResp.data.resultData && apiResp.data.resultData.runData) || {};

// First item of first main branch for a node (matches typical linear flows).
function nodeOutput(nodeName) {
  const runs = runData[nodeName];
  if (!runs || !runs.length) return null;
  const main = runs[0] && runs[0].data && runs[0].data.main;
  if (!main || !main.length) return null;
  const branch0 = main[0];
  if (!branch0 || !branch0.length) return null;
  const j = branch0[0].json;
  return j && typeof j === 'object' ? j : null;
}

// Low → high priority (later overwrites earlier). SetVars must win on sub-workflows.
const CONTEXT_NODE_ORDER = [
  'Router',
  'Parse AI Response',
  'AddUserName',
  'When Executed by Another Workflow',
  'ReadIncidentContext',
  'Read Incident Context',
  'SetVars',
];

let ctx = {};
let ctxSource = 'fallback';
for (const name of CONTEXT_NODE_ORDER) {
  const o = nodeOutput(name);
  if (!o) continue;
  ctx = { ...ctx, ...o };
  ctxSource = name;
}

function boolish(v) {
  if (v === true || v === false) return v;
  if (v === 'true') return true;
  if (v === 'false') return false;
  return null;
}

function computeThreadRootId(c) {
  const direct = c.reply_root_id || c.thread_root_id;
  if (direct) return String(direct);

  const inThreadFlag = boolish(c.is_thread) ?? boolish(c.is_in_thread);
  const slackStyleInThread =
    c.thread_ts && c.ts && String(c.thread_ts) !== String(c.ts);
  const inThread = inThreadFlag === true || (inThreadFlag === null && slackStyleInThread);

  if (inThread) {
    return String(c.thread_root_id || c.thread_ts || '');
  }
  return String(c.post_id || c.ts || c.thread_ts || '');
}

const replyRootId = computeThreadRootId(ctx);
const channelId = ctx.channel_id || cfg.fallback_channel_id;
const hasThread = Boolean(channelId && replyRootId);

function truncate(s, n) {
  if (!s) return '';
  return s.length > n ? s.slice(0, n) + '…' : s;
}

const errMsg = truncate(exec.error && exec.error.message, 1500) || 'Unknown error';
const lastNode = exec.lastNodeExecuted || 'unknown node';
const execUrl = exec.url || '';
const wfName = wf.name || 'unknown workflow';
const execMode = exec.mode || '';

const lines = [
  `:rotating_light: **${wfName}** execution failed`,
  '',
  `**Failed node:** \`${lastNode}\``,
  `**Error:**`,
  '```',
  errMsg,
  '```',
];

if (execUrl) {
  lines.push(`**Execution:** [open in n8n](${execUrl})`);
}
if (execMode) {
  lines.push(`**Mode:** ${execMode}`);
}
if (ctx.user_name) {
  lines.push(
    `**Original request from:** @${ctx.user_name}${ctx.channel_name ? ' in #' + ctx.channel_name : ''}`,
  );
}
if (!hasThread) {
  lines.push('');
  lines.push('_Note: thread context could not be recovered — posting to fallback channel._');
}

return [
  {
    json: {
      channel_id: channelId,
      root_id: replyRootId,
      message: lines.join('\n'),
      has_thread_context: hasThread,
      debug: {
        execution_id: exec.id,
        workflow_id: wf.id,
        context_source: ctxSource,
      },
    },
  },
];
